using System.Reflection;

var asm = Assembly.LoadFrom(
    Path.Combine(
        Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
        ".nuget/packages/microsoft.agents.ai/1.3.0/lib/net10.0/Microsoft.Agents.AI.dll"));

// Check return types of ChatClientAgent methods
var t = asm.GetExportedTypes().First(t => t.Name == "ChatClientAgent");
foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
    Console.WriteLine($"  {m.ReturnType} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType} {p.Name}"))})");

// Check AgentSession, AgentRunOptions, AIAgent base
Console.WriteLine("\n=== AgentSession ===");
var sessionType = asm.GetExportedTypes().FirstOrDefault(t => t.Name == "AgentSession");
if (sessionType != null)
{
    Console.WriteLine($"  Base: {sessionType.BaseType}");
    foreach (var c in sessionType.GetConstructors(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType} {p.Name}"))})");
    foreach (var p in sessionType.GetProperties())
        Console.WriteLine($"  prop {p.PropertyType} {p.Name}");
}

Console.WriteLine("\n=== AgentRunOptions ===");
var runOpts = asm.GetExportedTypes().FirstOrDefault(t => t.Name == "AgentRunOptions");
if (runOpts != null)
{
    foreach (var p in runOpts.GetProperties())
        Console.WriteLine($"  prop {p.PropertyType} {p.Name}");
}

Console.WriteLine("\n=== AIAgent base ===");
var aiAgent = asm.GetExportedTypes().FirstOrDefault(t => t.Name == "AIAgent");
if (aiAgent != null)
{
    foreach (var m in aiAgent.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
        Console.WriteLine($"  {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    foreach (var p in aiAgent.GetProperties())
        Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
