using System.ComponentModel;
using System.Text.Json;
using System.Text.RegularExpressions;

namespace ResearchAgent;

/// <summary>
/// Provides web search and note-taking tools for the research agent.
/// </summary>
public sealed partial class ResearchTools : IDisposable
{
    private readonly HttpClient _httpClient = new();
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Search the web for information on a topic. Returns relevant snippets from search results.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&format=json&srlimit=5&utf8=1";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0 (dotnet)");

            using var response = await _httpClient.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var json = await response.Content.ReadAsStringAsync(cancellationToken);
            using var doc = JsonDocument.Parse(json);

            var results = doc.RootElement
                .GetProperty("query")
                .GetProperty("search")
                .EnumerateArray()
                .Select(r =>
                {
                    var title = r.GetProperty("title").GetString() ?? "";
                    var snippet = StripHtml(r.GetProperty("snippet").GetString() ?? "");
                    return $"• {title}: {snippet}";
                })
                .ToList();

            return results.Count > 0
                ? $"Search results for '{query}':\n\n{string.Join("\n\n", results)}"
                : $"No results found for '{query}'.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note with a title and content. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The detailed content of the note")] string content)
    {
        _notes.Add((title, content));
        return $"Note #{_notes.Count} saved: '{title}'";
    }

    [Description("Retrieve all saved research notes. Use this before writing a final summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        return string.Join("\n\n---\n\n",
            _notes.Select((n, i) => $"Note #{i + 1}: {n.Title}\n{n.Content}"));
    }

    private static string StripHtml(string html) =>
        HtmlTagRegex().Replace(html, "");

    [GeneratedRegex("<.*?>")]
    private static partial Regex HtmlTagRegex();

    public void Dispose() => _httpClient.Dispose();
}

