using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using ResearchAgent;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient ---
IChatClient chatClient = new OpenAI.Chat.ChatClient(modelId, apiKey).AsIChatClient();

// --- Register tools ---
using var tools = new ResearchTools();
var aiTools = new AITool[]
{
    AIFunctionFactory.Create(tools.SearchWebAsync),
    AIFunctionFactory.Create(tools.SaveNote),
    AIFunctionFactory.Create(tools.GetNotes),
};

// --- Create the agent ---
const string instructions = """
    You are a research agent. Your job is to research a topic thoroughly and produce a
    well-organized summary. Follow this workflow:

    1. Break the topic into 2-3 sub-questions worth investigating.
    2. For each sub-question, use SearchWebAsync to find relevant information.
    3. After each search, use SaveNote to record the key findings with a descriptive title.
    4. Once you have gathered enough notes (at least 3), use GetNotes to review them.
    5. Write a final comprehensive summary that synthesizes all your notes, organized with
       clear headings and bullet points.

    Be thorough but concise. Cite the sources you found in your summary.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking tools.",
    tools: aiTools);

var chatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
};
var runOptions = new ChatClientAgentRunOptions(chatOptions);

// --- Get the research topic ---
string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "";
    if (string.IsNullOrEmpty(topic))
    {
        Console.WriteLine("No topic provided. Exiting.");
        return;
    }
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent with streaming ---
var session = await agent.CreateSessionAsync();

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();

