5. namespace ResearchAgent;
6. 
7. /// <summary>
8. /// Provides web search and note-taking tools for the research agent.
9. /// </summary>
10. public sealed partial class ResearchTools : IDisposable
11. {
12.     private readonly HttpClient _httpClient = new();
13.     private readonly List<(string Title, string Content)> _notes = [];
14. 
15.     [Description("Search the web for information on a topic. Returns relevant snippets from search results.")]
16.     public async Task<string> SearchWebAsync(
17.         [Description("The search query to look up")] string query,
18.         CancellationToken cancellationToken = default)
19.     {
20.         try
